#include <stdio.h>
#include <string.h>
#define MAXN 125005
char S[MAXN], T[MAXN];
int n, q;
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &n, &q);
        scanf("%s %s", S, T);
        while (q--) {
            int x, y;
            scanf("%d %d", &x, &y);
            // Find the LCP of S[x..n] and T[y..n]
            int lcp = 0;
            while (x <= n && y <= n && S[x-1] == T[y-1]) {
                lcp++;
                x++;
                y++;
            }
            // Find the optimal bijection
            char bij[11];
            for (int i = 0; i < 10; i++) {
                bij[i] = 'a' + i;
            }
            // Print the result
            printf("%d %s\n", lcp, bij);
        }
    }
    return 0;
}

